import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import ApplyJobForm from '../../features/lamaran/ApplyJobForm'; // Sesuaikan path ini dengan struktur folder Anda

const JobDetail = () => {
    const { id } = useParams();
    const navigate = useNavigate();

    // State untuk menampilkan formulir lamaran
    const [showApplyForm, setShowApplyForm] = useState(false);

    // Simulasi data (Ganti dengan integrasi API Anda)
    const job = { 
        id: id, 
        title: 'Fullstack Developer', 
        company: 'PasukanYerusSolo', 
        desc: 'Kami mencari pengembang yang antusias untuk membangun arsitektur web modern...' 
    };

    return (
        <div style={{ maxWidth: '800px', margin: '40px auto', padding: '20px', color: '#fef3c7' }}>
            <button onClick={() => navigate(-1)} style={{ background: 'none', border: 'none', color: '#a3a3a3', cursor: 'pointer', marginBottom: '20px' }}>
                ← Kembali
            </button>

            <div style={{ padding: '30px', background: '#120b06', borderRadius: '16px', border: '1px solid #262626' }}>
                <h1 style={{ color: '#ea580c' }}>{job.title}</h1>
                <p style={{ fontSize: '18px' }}>{job.company}</p>

                <div style={{ margin: '20px 0', padding: '20px 0', borderTop: '1px solid #262626' }}>
                    <h3>Deskripsi Pekerjaan</h3>
                    <p style={{ color: '#a3a3a3', lineHeight: '1.8' }}>{job.desc}</p>
                </div>

                {/* Tombol Aksi */}
                {!showApplyForm ? (
                    <button 
                        onClick={() => setShowApplyForm(true)}
                        style={{ padding: '12px 32px', background: '#ea580c', color: '#fff', border: 'none', borderRadius: '8px', fontWeight: 'bold', cursor: 'pointer' }}
                    >
                        Lamar Sekarang
                    </button>
                ) : (
                    <div style={{ marginTop: '20px', padding: '20px', background: '#1a120c', borderRadius: '12px' }}>
                        <h3 style={{ color: '#ea580c', marginTop: 0 }}>Kirim Lamaran Anda</h3>
                        {/* Integrasi Komponen ApplyJobForm */}
                        <ApplyJobForm 
                            jobId={id} 
                            onFormSuccess={() => setShowApplyForm(false)} 
                        />
                    </div>
                )}
            </div>
        </div>
    );
};

export default JobDetail;
